public Pet getPet(String name, boolean ignoreNew) {
	name = name.toLowerCase();
	for (Pet pet : getPets()) {
		String compName = pet.getName();
		if (compName != null && compName.equalsIgnoreCase(name)) {
			if (!ignoreNew || !pet.isNew()) {
				return pet;
			}
		}
	}
	return null;
}

